class Solution {
public:
    string baseNeg2(int n) {
        if (n == 0) return "0";
        string result = "";
        while (n != 0) {
            int remainder = n % -2;
            if (remainder >= 0) {
                result = "1" + result;
                n = n / -2 - 1;
            } else {
                result = "0" + result;
                n = n / -2;
            }
        }
        return result;
    }
};
```
